import logging
from flask import Flask, Response
from werkzeug.serving import run_simple

logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

class SimpleWSGIMiddleware:
    def __init__(self, app):
        self.app = app
        logging.info("SimpleWSGIMiddleware initialized.")

    def __call__(self, environ, start_response):
        path = environ.get('PATH_INFO', '/')
        method = environ.get('REQUEST_METHOD', 'GET')

        logging.info(f"Middleware pre-processing: Request received - Method: {method}, Path: {path}")

        def custom_start_response(status, headers, exc_info=None):
            headers.append(('X-Middleware-Processed', 'true'))
            logging.info(f"Middleware: Added header 'X-Middleware-Processed: true' to response.")
            return start_response(status, headers, exc_info)

        response_iterable = self.app(environ, custom_start_response)

        logging.info(f"Middleware post-processing completed for Path: {path}")

        return response_iterable

app = Flask(__name__)

@app.route('/')
def hello():
    return "Hello from Flask!"

@app.route('/test')
def test():
    return "Another test page."

wrapped_app = SimpleWSGIMiddleware(app)

if __name__ == '__main__':
    logging.info("Starting Flask application wrapped with SimpleWSGIMiddleware.")
    run_simple('127.0.0.1', 5000, wrapped_app, use_reloader=True, use_debugger=True)
